const thread_id = $input.first().json.mail.thread_id
const current_mail_id = $input.first().json.mail.message_id

const mails_in_thread = $('Example Mail Thread').all().find(x => x.json.thread_id == thread_id)

const prev_mail = {
  prev_mail: []
}

if (mails_in_thread) {
  for  (const m of mails_in_thread.json.emails) {
    if (m.message_id !== current_mail_id) {
      prev_mail.prev_mail.push((m))
    } else {
      break
    }
  }
}

return prev_mail

const combinedPattern = /(\d{4}-\d{4}|[a-zA-Z]{2}\d{4}-\d{3,4}|PO-\d{4}-\d{3,4})/g;

const subject = $input.first().json.mail.subject

// Lấy tất cả matches
const matches = subject.match(combinedPattern);

return {
  ids: matches
}

const order = $input.all().find(x => x.json.order)
const incoming_mail = $input.all().find(x => x.json.mail)
const previous_mails = $input.all().find(x =>x.json.prev_mail)

if(!order || !incoming_mail) {
  return {
    isFail: true
  }
}

let content = `**Here is order information:
${JSON.stringify(order.json,null,2)}
**Here is incoming email:
${JSON.stringify(incoming_mail.json,null,2)}
`

if (previous_mails && previous_mails.json.prev_mail.length) {
  content += `**Here is previous email:\n`
  const sortedList = previous_mails.json.prev_mail.sort((a, b) => {
    return new Date(b.date).getTime() - new Date(a.date).getTime();
  });  
  for (let i = 0; i < sortedList.length; i ++) {
    content += `---Mail: ${i+1}---
${JSON.stringify(sortedList[i],2,4)}
`
  }
}

return {
  content: content,
  isFail: false
}

