const orderId = $('Assemble Data').all()[0].json.order.order_id;
const emailId = $("A mail come in").first().json.mail.message_id;
const createdAt = $now;
const summary = $('Information Extractor').first().json.output.summary.replace(/'/g, "''");

const queriesAndLogs = $input.all();
const queries = []
const logs = []
for (let idx = 0; idx < queriesAndLogs.length; idx++) {
  const element = queriesAndLogs[idx];
  queries.push(element.json.query)
  logs.push(element.json.log)
}

const jsonLogs = JSON.stringify(logs)

const insertEtaHandledLogs = `INSERT INTO "EtaHandledLogs" ("poId", "emailId", "handledAt", "logs", "summary")
values ('${orderId}','${emailId}', '${createdAt}','${jsonLogs}', '${summary}');
`

const finalQuery = `
DO $aaa$ 
BEGIN
  BEGIN
    ${queries.join('\n')}
    ${insertEtaHandledLogs}
  RAISE NOTICE 'Transaction completed successfully';

    EXCEPTION
        WHEN OTHERS THEN
            RAISE NOTICE 'Error occurred: %', SQLERRM;
            RAISE;
    END;
END $aaa$;
`

return {
  finalQuery
}
